import React, { Component } from 'react';
import './App.css'

let timeId = null;

class App extends Component {
  constructor(props) {
    super(props);
    this.state = {
      breakLength: 5,
      sessionLength: 25,
      timeLeft: 1500,
      running: false,
      currentTimer: 'Session',
      switch: 'START',
    }
    
    this.clockify = this.clockify.bind(this);
    this.reset = this.reset.bind(this);
    this.decrement = this.decrement.bind(this);
    this.increment = this.increment.bind(this);
    this.switch = this.switch.bind(this);
    this.startBreak = this.startBreak.bind(this);
    this.startSession = this.startSession.bind(this)
  }

  
  clockify() {
    let minutes = Math.floor(this.state.timeLeft / 60);
    let seconds = this.state.timeLeft - minutes * 60
    seconds = seconds < 10 ? '0' + seconds : seconds;
    minutes = minutes < 10 ? '0' + minutes : minutes;
    return minutes + ':' + seconds;
  }

  reset() {
    clearInterval(timeId);
    timeId = null;
    this.setState({
      breakLength: 5,
      sessionLength: 25,
      timeLeft: 1500,
      running: false,
      currentTimer: 'Session',
      
    })
    let sound = document.getElementById('beep');
           sound.pause();
           sound.currentTime = 0

  }

  decrement(e) {
    if (this.state.running) {return}
    if (e.target.id == 'break-decrement') {
      if (this.state.breakLength > 1) {
        this.setState({
          breakLength: this.state.breakLength - 1
        })
      } 
    } else {
      if (this.state.sessionLength > 1) {
        this.setState({
          sessionLength: this.state.sessionLength - 1,
          timeLeft: (this.state.sessionLength - 1) * 60
        })
      }
    }
  }
  increment(e) {
    if (this.state.running) {return}
    if (e.target.id == 'break-increment') {
      if (this.state.breakLength < 60) {
        this.setState({
          breakLength: this.state.breakLength + 1
          
        })
      } 
    } else {
      if (this.state.sessionLength < 60) {
        this.setState({
          sessionLength: this.state.sessionLength + 1,
          timeLeft: (this.state.sessionLength + 1) * 60
        })
      }
    }
  }

  

  switch() {
    
    this.setState({
      running: !this.state.running
    }, ()=> {(this.state.running) ? timeId = setInterval(() => {
      this.setState({
        timeLeft: this.state.timeLeft - 1
      }, function() {
        if (this.state.timeLeft < 0) {
          clearInterval(timeId)
          let sound = document.getElementById('beep');
           sound.play();
           if (this.state.currentTimer == 'Session') {
             this.startBreak()
           } else {
             this.startSession();
           }
        }
      })
    }, 1000) : clearInterval(timeId)} );
    
  }

  startBreak() {
    
    this.setState({
      timeLeft: this.state.breakLength * 60,
      currentTimer: 'Break',
      running: false
    }, this.switch)
  }

  startSession() {
    
    this.setState({
      timeLeft: this.state.sessionLength * 60,
      currentTimer: 'Session',
      running:false
    }, this.switch)
  }
  
  render() {
    return (
      <div id = 'clock'>
        <h1 id = 'header'>Pomodoro clock</h1>
        <div id = 'timer-adjust'>

          <div id = 'break'>
            <div id = 'break-label'>
              Break Length
            </div>

            <div id = 'break-adjust'>
              <div id = 'break-decrement' onClick = {this.decrement}>-</div>
              <div id = 'break-length'>
               {this.state.breakLength}
              </div>
             <div id = 'break-increment' onClick = {this.increment}>+</div>
          </div>

        </div>
        
        <div id = 'session'>
          <div id = 'session-label'>
            Session Length
          </div>
          <div id = 'session-adjust'>
            <div id = 'session-decrement' onClick = {this.decrement}>-</div>
            <div id = 'session-length'>
              {this.state.sessionLength}
            </div>
            <div id = 'session-increment' onClick = {this.increment}>+</div>
          </div>
        </div>
        
      </div>


        <div id = 'timer'>
          
          <div id = 'timer-label'>{this.state.currentTimer}</div>
          <div id = 'time-left'>
            {this.clockify()}
          </div>
          
        </div>

        <div id = 'timer-control'>
    <div id = 'start_stop' onClick = {this.switch}>{this.state.running? 'STOP' : 'START'}</div>
          <div id = 'reset' onClick = {this.reset}>RESET</div>
        </div> 
       
        <footer id = 'author'>
          Design and coded by Yaosong Hu
        </footer>
        <audio id = 'beep' src="http://www.peter-weinberg.com/files/1014/8073/6015/BeepSound.wav"></audio>
      </div>
    );
  }
}

export default App;